SELECT is_valid, COUNT(*) AS validation_count
FROM address_validations
GROUP BY is_valid;

SELECT COUNT(*) AS number_of_valid_addresses
FROM address_validations
WHERE is_valid = 1;

SELECT COUNT(*) AS change_count
FROM address_changes
WHERE change_date = '2023-05-01';

SELECT COUNT(*) AS search_count
FROM address_searches
WHERE user_id = 1;

SELECT user_id, COUNT(change_id) AS number_of_changes
FROM address_changes
GROUP BY user_id;

SELECT validation_date, validation_reason
FROM address_validations
WHERE validation_id = (
  SELECT MAX(validation_id)
  FROM address_validations
);

SELECT search_location, COUNT(*) AS total_searches
FROM address_searches
GROUP BY search_location;

SELECT COUNT(DISTINCT user_id) AS unique_users_count
FROM address_searches
WHERE search_date = '2023-05-01';

SELECT COUNT(*) AS total_searches
FROM address_searches
WHERE search_date >= '2023-05-01';
